mapper.select:
SELECT *
FROM(
    SELECT rownum rn
        , r.*
    FROM(
        SELECT *
        FROM productReview
        WHERE pno=#{pno}
        order by rnum desc
    )r
)
WHERE rn
    BETWEEN (#{cri.pageNum} - 1) * #{cri.amount} + 1 AND #{cri.pageNum} * #{cri.amount}

SELECT count(*)
FROM productReview
WHERE pno=#{pno}

SELECT count(*)
FROM productQnA
WHERE pno=#{pno}

SELECT count(*)
FROM like_product
WHERE userId=#{userId}
    AND pno=#{pno}

SELECT count(*)
FROM cart
WHERE cartNo=#{cartNo}

mapper.insert:
INSERT INTO cart(
    cartNo
    , userId
    , pOpNo
    , cCount
    , cPrice
)
VALUES(
    #{cartNo}
    , #{userId}
    , #{pOpNo}
    , #{cCount}
    , #{cPrice}
)

mapper.update:
UPDATE cart SET
    cCount=cCount + #{cCount}
    , cPrice=cPrice + #{cPrice}
WHERE cartNo=#{cartNo}

mapper.insert:
INSERT INTO productQnA(
    pQnANo
    , pno
    , userId
    , pQnAContent
    , pQnARegDate
    , pQnAGroupNo
)
values(
    product_QnA_SEQ.NEXTVAL
    , #{pno}
    , #{userId}
    , #{pQnAContent}
    , sysdate
    , product_QnA_SEQ.NEXTVAL
)

INSERT INTO like_Product(
    likeNo
    , userId
    , pno
)
VALUES(
    #{likeNo}
    , #{userId}
    , #{pno}
)

mapper.delete:
DELETE FROM like_product
WHERE userId=#{userId}
    AND pno=#{pno}
